CREATE TABLE IF NOT EXISTS public.adapted_diets (id UUID NOT NULL DEFAULT gen_random_uuid() PRIMARY KEY, user_id UUID NOT NULL REFERENCES auth.users ON DELETE CASCADE, titulo TEXT NOT NULL DEFAULT 'Dieta adaptada', source_type TEXT NOT NULL, personalization JSONB NOT NULL DEFAULT '{}'::jsonb, resultado JSONB NOT NULL, compatibilidade INT, created_at TIMESTAMPTZ NOT NULL DEFAULT now()); GRANT SELECT, INSERT, UPDATE, DELETE ON public.adapted_diets TO authenticated; GRANT ALL ON public.adapted_diets TO service_role; ALTER TABLE public.adapted_diets ENABLE ROW LEVEL SECURITY; DROP POLICY IF EXISTS "Users manage own adapted diets" ON public.adapted_diets; CREATE POLICY "Users manage own adapted diets" ON public.adapted_diets FOR ALL USING (auth.uid() = user_id) WITH CHECK (auth.uid() = user_id); CREATE INDEX IF NOT EXISTS adapted_diets_user_created_idx ON public.adapted_diets(user_id, created_at DESC);